#!/usr/bin/env python3
import json
import csv
import pandas as pd

# Field name -> unified name
FIELD_MAP = {
    "user_id": "user_id", "id": "user_id", "userId": "user_id",
    "email": "email", "email_address": "email",
    "full_name": "name", "name": "name", "userName": "name",
    "registration_date": "created_date", "created_at": "created_date", "joined": "created_date",
    "status": "status", "is_active": "status", "active": "status",
}


def normalize_status(v):
    if isinstance(v, bool):
        return "active" if v else "inactive"
    if isinstance(v, str):
        s = v.strip().lower()
        if s in ("true", "1"):
            return "active"
        if s in ("false", "0"):
            return "inactive"
        return v
    return v


def normalize_date(v):
    if v is None:
        return None
    return pd.to_datetime(str(v)).strftime("%Y-%m-%d")


def normalize_record(raw):
    """Map source fields to unified names."""
    rec = {}
    for k, v in raw.items():
        if k not in FIELD_MAP or v is None:
            continue
        uk = FIELD_MAP[k]
        if uk == "user_id":
            rec[uk] = int(v)
        elif uk == "created_date":
            rec[uk] = normalize_date(v)
        elif uk == "status":
            rec[uk] = normalize_status(v)
        else:
            rec[uk] = str(v)
    return rec


# ---- Read source A (JSON) ----
with open("/data/source_a/users.json") as f:
    raw_a = json.load(f)
source_a = {int(r["id"] if "id" in r else r.get("user_id", r.get("userId"))): normalize_record(r) for r in raw_a}

# ---- Read source B (CSV) ----
source_b = {}
with open("/data/source_b/users.csv", newline="") as f:
    for row in csv.DictReader(f):
        rec = normalize_record(row)
        source_b[rec["user_id"]] = rec

# ---- Read source C (Parquet) ----
df_c = pd.read_parquet("/data/source_c/users.parquet")
source_c = {}
for row in df_c.to_dict("records"):
    rec = normalize_record(row)
    source_c[rec["user_id"]] = rec

sources = [("source_a", source_a), ("source_b", source_b), ("source_c", source_c)]

# All unique user ids
all_ids = sorted(set(source_a) | set(source_b) | set(source_c))

FIELDS = ["name", "email", "created_date", "status"]

merged = []
conflicts = []

for uid in all_ids:
    present = [(sname, sdata[uid]) for sname, sdata in sources if uid in sdata]
    merged_rec = {"user_id": uid}
    for field in FIELDS:
        # values by source (only sources that have this field)
        vals = {sname: rec[field] for sname, rec in present if field in rec}
        if not vals:
            merged_rec[field] = None
            continue
        # highest priority source (present list is already in priority order)
        selected = None
        for sname, rec in present:
            if field in rec:
                selected = rec[field]
                break
        merged_rec[field] = selected
        # conflict: user in multiple sources with differing values for this field
        distinct = set(vals.values())
        if len(vals) > 1 and len(distinct) > 1:
            conflicts.append({
                "user_id": uid,
                "field": field,
                "values": vals,
                "selected": selected,
            })
    merged.append(merged_rec)

# ---- Write merged parquet ----
out = pd.DataFrame(merged, columns=["user_id", "name", "email", "created_date", "status"])
out["user_id"] = out["user_id"].astype("int64")
for c in ["name", "email", "created_date", "status"]:
    out[c] = out[c].astype("object")
out.to_parquet("/app/merged_users.parquet", index=False)

# ---- Write conflict report ----
report = {"total_conflicts": len(conflicts), "conflicts": conflicts}
with open("/app/conflicts.json", "w") as f:
    json.dump(report, f, indent=2)

print("merged rows:", len(merged))
print(out.to_string())
print("total_conflicts:", len(conflicts))
print(json.dumps(report, indent=2))

